prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org ?defs ?choreo WHERE {
  ?model a bboExt:Model .
  FILTER(?model = <https://www.teamingai-project.eu/1c273a0818b146269ac04f6b8d518698> || 
         ?model = <http://www.onto-bpo.eu/ontologies/bbo#1c273a0818b146269ac04f6b8d518698> ||
         tai:normalizedId(?model) = "1c273a0818b146269ac04f6b8d518698" ||
         tai:originalId(?model) = "1c273a0818b146269ac04f6b8d518698")
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  OPTIONAL { ?defs tai:belongsTo ?model . }
  OPTIONAL { ?choreo tai:belongsTo ?defs . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(LCASE(STR(?origId)), "1c273a0818b146269ac04f6b8d518698") ||
         CONTAINS(LCASE(STR(?normId)), "1c273a0818b146269ac04f6b8d518698") ||
         CONTAINS(LCASE(STR(?model)), "1c273a0818b146269ac04f6b8d518698"))
}
LIMIT 25
